script:
const $r = root_element;
const $ = (sel) => $r.querySelector(sel);

const PROVIDERS = { "Claude (default)": "Claude", "OpenAI": "OpenAI", "Gemini": "Gemini" };
const SCANNED = { "AI Vision (auto-detect)": "ai_vision", "Local OCR (tesseract)": "ocr", "Skip scanned": "skip" };

const escape = (s) => frappe.utils.escape_html(s == null ? "" : String(s));

function loadCompanies() {
  return frappe.call({
    method: "frappe.client.get_list",
    args: { doctype: "Company", fields: ["name"], limit: 50 }
  }).then((r) => {
    $("#ai-company").innerHTML = (r.message || [])
      .map(c => `<option>${escape(c.name)}</option>`).join("");
  });
}

function bindEvents() {
  const zone = $("#ai-drop-zone");
  const input = $("#ai-file-input");
  const btn = $("#ai-upload-btn");

  zone.addEventListener("dragover", (e) => { e.preventDefault(); zone.classList.add("drag-over"); });
  zone.addEventListener("dragleave", () => zone.classList.remove("drag-over"));
  zone.addEventListener("drop", (e) => {
    e.preventDefault();
    zone.classList.remove("drag-over");
    if (e.dataTransfer.files.length) uploadFiles(e.dataTransfer.files);
  });
  zone.addEventListener("click", () => input.click());
  input.addEventListener("change", () => { if (input.files.length) uploadFiles(input.files); });
  btn.addEventListener("click", () => input.click());
}

function uploadFiles(files) {
  const company = $("#ai-company").value;
  if (!company) { frappe.msgprint("Please select a Company before uploading."); return; }
  const provider = PROVIDERS[$("#ai-provider").value] || "Claude";
  const scanned = SCANNED[$("#ai-scanned").value] || "ai_vision";

  const prog = $("#ai-upload-progress");
  prog.style.display = "block";
  prog.className = "";
  prog.textContent = `Uploading ${files.length} file(s)…`;

  Promise.all(Array.from(files).map(f => uploadOne(f, company, provider, scanned)))
    .then((results) => {
      const flat = results.flat();
      prog.className = "success";
      prog.innerHTML = `✓ ${flat.length} import job(s) queued: <strong>${flat.map(escape).join(", ")}</strong>`;
      refreshJobs();
      $("#ai-file-input").value = "";
    })
    .catch((err) => {
      prog.className = "error";
      prog.textContent = "Upload failed: " + (err.message || err);
    });
}

function uploadOne(file, company, provider, scanned) {
  const fd = new FormData();
  fd.append("file", file);
  fd.append("company", company);
  fd.append("provider", provider);
  fd.append("scanned_mode", scanned);
  return fetch("/api/method/erpnext_ai_importer.api.upload.upload_invoice", {
    method: "POST",
    headers: { "X-Frappe-CSRF-Token": frappe.csrf_token },
    body: fd,
  }).then(r => r.json()).then(data => {
    if (data.exc) throw new Error(data._server_messages || data.exc);
    return data.message || [];
  });
}

function refreshJobs() {
  return frappe.call({
    method: "frappe.client.get_list",
    args: {
      doctype: "AI Document Import",
      fields: [
        "name","company","supplier","extracted_supplier_name",
        "total","status","purchase_invoice","source_file","creation","supplier_match_score"
      ],
      order_by: "creation desc",
      limit: 50,
    },
  }).then(r => renderJobs(r.message || []));
}

function renderJobs(rows) {
  const count = $("#ai-job-count");
  const list = $("#ai-job-list");
  if (!rows.length) {
    count.textContent = "";
    list.innerHTML = `<div class="empty">No imports yet — upload a supplier invoice to get started.</div>`;
    return;
  }
  count.textContent = `Showing ${rows.length}`;
  const tbody = rows.map(r => `<tr>
    <td>${fileIcon(r.source_file)} ${escape(fileName(r))}</td>
    <td>${escape(r.company || "—")}</td>
    <td>${supplierCell(r)}</td>
    <td>${r.total ? frappe.format(r.total, {fieldtype:"Currency"}) : "—"}</td>
    <td>${statusBadge(r.status)}</td>
    <td>${actionCell(r)}</td>
  </tr>`).join("");
  list.innerHTML = `<table class="ai-jobs-table">
    <thead><tr>
      <th>File</th><th>Company</th><th>Supplier (matched)</th>
      <th>Total</th><th>Status</th><th>Action</th>
    </tr></thead>
    <tbody>${tbody}</tbody>
  </table>`;
}

function fileName(r) {
  return r.source_file ? r.source_file.split("/").pop() : r.name;
}
function fileIcon(sf) {
  if (!sf) return "📄";
  const ext = sf.split(".").pop().toLowerCase();
  if (ext === "zip") return "📦";
  if (["xlsx","xls","csv"].includes(ext)) return "📊";
  return "📄";
}
function supplierCell(row) {
  if (!row.supplier) {
    if (row.extracted_supplier_name) return `<span style="color:#dc2626">⚠ No match for "${escape(row.extracted_supplier_name)}"</span>`;
    return "—";
  }
  const score = row.supplier_match_score || 0;
  const color = score >= 85 ? "#16a34a" : score >= 60 ? "#d97706" : "#dc2626";
  return `<span style="color:${color}">${escape(row.supplier)}</span> <span style="font-size:0.78em;color:#94a3b8;margin-left:4px">${score}%</span>`;
}
function statusBadge(status) {
  const map = {
    "Draft":              { bg:"#f1f5f9", color:"#475569", icon:"○" },
    "Extracting":         { bg:"#dbeafe", color:"#1e40af", icon:"⚙" },
    "Pending Validation": { bg:"#fef3c7", color:"#92400e", icon:"⏳" },
    "Submitted":          { bg:"#dcfce7", color:"#166534", icon:"✓" },
    "Failed":             { bg:"#fee2e2", color:"#991b1b", icon:"✕" },
  };
  const s = map[status] || { bg:"#f1f5f9", color:"#374151", icon:"" };
  return `<span class="ai-status-badge" style="background:${s.bg};color:${s.color}">${s.icon} ${escape(status||"")}</span>`;
}
function actionCell(row) {
  if (row.status === "Submitted" && row.purchase_invoice) {
    const url = frappe.utils.get_form_link("Purchase Invoice", row.purchase_invoice);
    return `<a href="${url}" style="color:#4f46e5;font-size:0.85em">${escape(row.purchase_invoice)}</a>`;
  }
  if (row.status === "Pending Validation" || row.status === "Failed") {
    const url = "/app/ai-invoice-validate/" + encodeURIComponent(row.name);
    const label = row.status === "Failed" ? "View →" : "Validate →";
    return `<a href="${url}" style="color:#4f46e5;font-size:0.85em">${label}</a>`;
  }
  if (row.status === "Extracting") return `<span style="color:#64748b;font-size:0.82em">Processing…</span>`;
  const url = "/app/ai-invoice-validate/" + encodeURIComponent(row.name);
  return `<a href="${url}" style="color:#64748b;font-size:0.85em">View →</a>`;
}

loadCompanies().then(() => {
  bindEvents();
  refreshJobs();
  setInterval(refreshJobs, 10000);
});

style:
#ai-importer-root { max-width:960px; margin:0 auto; padding:16px; }
#ai-importer-nav { display:flex; gap:8px; justify-content:flex-end; margin-bottom:12px; }
#ai-importer-nav a { color:#4f46e5; text-decoration:none; font-size:0.85em; padding:4px 10px; border-radius:4px; border:1px solid transparent; }
#ai-importer-nav a:hover { background:#eef2ff; border-color:#c7d2fe; }
#ai-importer-grid { display:grid; grid-template-columns:1fr 240px; gap:16px; align-items:start; margin-bottom:24px; }
#ai-drop-zone { border:2px dashed #a5b4fc; border-radius:8px; padding:48px 32px; text-align:center; background:#f5f3ff; cursor:pointer; transition:background 0.15s; }
#ai-drop-zone .emoji { font-size:2.4em; margin-bottom:8px; }
#ai-drop-zone .title { font-weight:600; color:#4f46e5; font-size:1.05em; }
#ai-drop-zone .hint { font-size:0.82em; color:#64748b; margin-top:6px; }
#ai-drop-zone.drag-over { background:#ede9fe; }
#ai-file-input { display:none; }
#ai-options { background:#f8fafc; border:1px solid #e2e8f0; border-radius:8px; padding:16px; font-size:0.85em; }
#ai-options .opt-title { font-weight:600; color:#374151; margin-bottom:12px; font-size:0.9em; text-transform:uppercase; letter-spacing:0.04em; }
#ai-options .opt-row { margin-bottom:10px; }
#ai-options .opt-row:last-of-type { margin-bottom:14px; }
#ai-options .opt-label { color:#374151; margin-bottom:4px; }
#ai-options select { width:100%; border:1px solid #cbd5e1; border-radius:4px; padding:6px; background:#fff; }
#ai-upload-btn { width:100%; background:#4f46e5; color:#fff; border:none; border-radius:4px; padding:9px; font-size:0.9em; cursor:pointer; font-weight:500; }
#ai-upload-progress { display:none; margin-bottom:16px; padding:12px 16px; background:#eff6ff; border:1px solid #bfdbfe; border-radius:6px; font-size:0.85em; color:#1e40af; }
#ai-upload-progress.success { background:#f0fdf4; border:1px solid #bbf7d0; color:#166534; }
#ai-upload-progress.error { background:#fef2f2; border:1px solid #fecaca; color:#991b1b; }
#ai-jobs-card { background:#fff; border:1px solid #e2e8f0; border-radius:8px; overflow:hidden; }
#ai-jobs-header { display:flex; justify-content:space-between; align-items:center; padding:12px 16px; border-bottom:1px solid #e2e8f0; }
#ai-jobs-header .ttl { font-weight:600; color:#374151; }
#ai-job-count { font-size:0.8em; color:#64748b; }
#ai-job-list .empty { padding:32px; text-align:center; color:#94a3b8; font-size:0.9em; }
.ai-jobs-table { width:100%; border-collapse:collapse; font-size:0.85em; }
.ai-jobs-table thead tr { background:#f8fafc; text-align:left; font-size:0.8em; color:#64748b; text-transform:uppercase; letter-spacing:0.04em; }
.ai-jobs-table th { padding:9px 12px; font-weight:500; }
.ai-jobs-table tbody tr { border-bottom:1px solid #f1f5f9; }
.ai-jobs-table td { padding:9px 12px; color:#374151; }
.ai-status-badge { padding:3px 10px; border-radius:4px; font-size:0.82em; white-space:nowrap; display:inline-block; }
